import { useState, useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";

const PRE_GENERATED_LANGS = ["zh", "en", "pt", "fr", "es"];

interface RecipeNameFields {
  recipe_name: string;
  recipe_name_en?: string;
  recipe_name_pt?: string;
  recipe_name_fr?: string;
  recipe_name_es?: string;
}

/**
 * Returns a localized recipe name. For zh/en/pt, uses pre-generated fields.
 * For other languages, triggers on-demand translation and caches the result.
 */
export const useRecipeTranslatedName = (recipe: RecipeNameFields | null) => {
  const { i18n } = useTranslation();
  const [translatedName, setTranslatedName] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const cacheRef = useRef<Record<string, string>>({});

  const lang = i18n.language;
  const recipeName = recipe?.recipe_name || "";
  const recipeNameEn = recipe?.recipe_name_en || "";

  // Get the best available pre-generated name
  const getPreGeneratedName = useCallback(() => {
    if (!recipe) return "";
    if (lang === "en" && recipe.recipe_name_en) return recipe.recipe_name_en;
    if (lang === "pt" && recipe.recipe_name_pt) return recipe.recipe_name_pt;
    if (lang === "fr" && recipe.recipe_name_fr) return recipe.recipe_name_fr;
    if (lang === "es" && recipe.recipe_name_es) return recipe.recipe_name_es;
    // For non-core languages, fall back to EN first, then ZH
    if (!PRE_GENERATED_LANGS.includes(lang) && recipe.recipe_name_en) return recipe.recipe_name_en;
    return recipe.recipe_name;
  }, [recipe, lang]);

  useEffect(() => {
    if (!recipe || PRE_GENERATED_LANGS.includes(lang)) {
      setTranslatedName(null);
      return;
    }

    const cacheKey = `${lang}_${recipeName}`;
    if (cacheRef.current[cacheKey]) {
      setTranslatedName(cacheRef.current[cacheKey]);
      return;
    }

    const doTranslate = async () => {
      setIsTranslating(true);
      try {
        const sourceText = recipeNameEn || recipeName;
        const { data, error } = await supabase.functions.invoke("translate-content", {
          body: { text: sourceText, targetLang: lang },
        });
        if (!error && data?.translatedText) {
          cacheRef.current[cacheKey] = data.translatedText;
          setTranslatedName(data.translatedText);
        }
      } catch {
        // keep fallback
      } finally {
        setIsTranslating(false);
      }
    };

    doTranslate();
  }, [lang, recipeName, recipeNameEn]);

  const displayName = translatedName || getPreGeneratedName();

  return { displayName, isTranslating };
};
